        val v = edgeArr(1).toInt
        val w = edgeArr(2)

        maxWeight = math.max(maxWeight, w)

        if (u >= 0 && u < N && v >= 0 && v < N) {
            adj(u).append(AdjEdge(v, w))
            adj(v).append(AdjEdge(u, w))
        }
    }

